{
  "analysis": "ffmpeg, ffprobe, tesseract, and pip3 are now installed and verified. No video metadata or frames have been extracted yet. We need inspect the video, install Python OCR/image helpers, extract sample frames, and assess OCR readability before building the move extraction pipeline.",
  "plan": "Run ffprobe for duration/resolution/frame rate, verify pip3, install Pillow/pytesseract/numpy/opencv-headless, create a work directory, extract sample frames at several timestamps, and run OCR on those samples to understand the Zork screen layout.",
  "commands": [
    {
      "keystrokes": "pip3 --version 2>&1\n",
      "duration": 0.1
    },
    {
      "keystrokes": "ffprobe -v error -select_streams v:0 -show_entries stream=width,height,r_frame_rate,nb_frames,duration -show_entries format=duration,size -of default=noprint_wrappers=1 /app/video.mp4 2>&1\n",
      "duration": 1.0
    },
    {
      "keystrokes": "pip3 install --break-system-packages Pillow pytesseract numpy opencv-python-headless 2>&1 | tail -10\n",
      "duration": 60.0
    },
    {
      "keystrokes": "mkdir -p /app/work/frames /app/work/ocr /app/work/logs\n",
      "duration": 0.1
    },
    {
      "keystrokes": "for t in 2 10 30 60 120 300 600 900 1200 1500 1800; do ffmpeg -hide_banner -loglevel error -y -ss \"$t\" -i /app/video.mp4 -frames:v 1 \"/app/work/sample_${t}s.png\"; done; ls -lh /app/work\n",
      "duration": 5.0
    },
    {
      "keystrokes": "python3 - <<'PY'\nfrom PIL import Image\nimport pytesseract, glob, os\nfor p in sorted(glob.glob('/app/work/sample_*s.png'), key=lambda s: int(s.rsplit('_',1)[1].rstrip('s.png'))):\n    im=Image.open(p)\n    print('\\\\n====', os.path.basename(p), im.size, '====')\n    txt=pytesseract.image_to_string(im)\n    print(txt[:3000])\nPY\n",
      "duration": 2.0
    }
  ]
}
